    String getFilterDetail( String filterStrings , String sepSymbol , NUIForm form ){
        String []filters = filterStrings.split(sepSymbol);
        StringBuilder stringBuilder = new StringBuilder();
        int sortOrder = 0;
        try {
            for( String filterString : filters ){
                if(filterString.isEmpty())continue;
                String []temp = filterString.split("\\|");
                //System.out.println("filterString:"+filterString);
                String domainId = temp[0];
                int operator = Integer.parseInt(temp[1]);
                String value = temp[temp.length-1];
                stringBuilder.append("針對欄位&nbsp;");
                CellInfo info = form.getField(Integer.parseInt(domainId));
                if( info == null ){ //這個欄位在列表頁找不到，表式使用者沒放在列表頁，那就從表單頁去找看看
                    NUIForm sheet = AppManager.getFormPage(form.getApname(), form.getPath(), form.getFormName(),true);
                    info = sheet.getField(Integer.parseInt(domainId));
                }
                stringBuilder.append(domainId).append("(").append(info).append(")");
                stringBuilder.append("&nbsp;做&nbsp;").append(this.operatorTran.getOrDefault(operator,operator+""));
                if( NUIFilter.isSortingOperand(operator) ){ //如果是排序的話，顯示排序順序和方向
                    sortOrder++;
                    stringBuilder.append(sortOrder);
                    if( sortOrder == 1 )
                        stringBuilder.append("(").append("主要排序").append(")");
                    stringBuilder.append("&nbsp;方向為:");
                    boolean ASC = operator == NUIFilter.OPERAND_SORT_ASC || operator == NUIFilter.OPERAND_SECONDARY_SORT_ASC;
                    boolean DESC = operator == NUIFilter.OPERAND_SORT_DESC || operator == NUIFilter.OPERAND_SECONDARY_SORT_DESC;
                    if( ASC ){
                        if( info.isDate() )
                            stringBuilder.append("舊到新");
                        else if( info.isNumeric() )
                            stringBuilder.append("小到大");
                        else if( info.isText() || info.isSelection() )
                            stringBuilder.append("A到Z");
                    }else if( DESC ){
                        if( info.isDate() )
                            stringBuilder.append("新到舊");
                        else if( info.isNumeric() )
                            stringBuilder.append("大到小");
                        else if( info.isText() || info.isSelection() )
                            stringBuilder.append("Z到A");
                    }
                }
                else{ //如果不是排序才顯示值(因為排序本來就沒有篩選值)
                    stringBuilder.append("&nbsp;值為&nbsp;");
                    if( operator == NUIFilter.OPERAND_SS ) //如果是特殊篩選
                        stringBuilder.append(this.specialOperatorTran.getOrDefault(value,value));
                    else{ //非特殊篩選
                        value = Encoder.decodeURIComponent(value);
                        if( operator == NUIFilter.OPERAND_LK ){
                            if( value.startsWith("\\Q") && value.endsWith("\\E") )
                                value = value.substring(2,value.length()-2);
                        }
                        stringBuilder.append(value);
                    }
                }

                stringBuilder.append("&#10;");//&#10;是title裡面 換行 的意思
            }
        } catch (Exception e) {
            return "";
        }
        return stringBuilder.toString();
    }

